def detecter_anomalie_horaire(username, heure_connexion, baseline):
    """Détecte une connexion hors des heures habituelles."""
    if username not in baseline:
        return {"anomalie": False, "raison": "Utilisateur inconnu"}

    heures_normales = baseline[username]["heures_connexion"]
    if heure_connexion not in heures_normales:
        return {
            "anomalie": True,
            "severite": "HAUTE",
            "raison": f"Connexion à {heure_connexion}h hors baseline ({min(heures_normales)}-{max(heures_normales)}h)"
        }
    return {"anomalie": False}

def detecter_anomalie_ip(username, ip_source, baseline):
    """Détecte une connexion depuis une IP inconnue."""
    if username not in baseline:
        return {"anomalie": False}

    ips_habituelles = baseline[username]["ips_habituelles"]
    if ip_source not in ips_habituelles:
        return {
            "anomalie": True,
            "severite": "MOYENNE",
            "raison": f"IP {ip_source} inconnue (habituelles: {ips_habituelles})"
        }
    return {"anomalie": False}

